mapper.select:
select exists (
    select 1
    from osh_course c
    left join osh_column_course occ
        on occ.course_id = c.id
       and occ.column_id = #{columnId}
    where c.id = #{courseId}
      and (c.column_id = #{columnId} or occ.id is not null)
)

select c.id, c.user_id, ifnull(u.username, '') as username, ifnull(u.username, '') as nickname, ifnull(u.avatar, '') as avatar, c.parent_id, p.user_id as parent_user_id, ifnull(pu.username, '') as parent_nickname, c.content, c.like_count, c.reply_count, c.status, c.create_time, c.update_time from osh_comment c inner join osh_comment p on p.id = c.parent_id inner join osh_comment_relation cr on cr.comment_id = p.id and cr.biz_type = #{bizType} and cr.biz_id = #{courseId} left join osh_user u on u.id = c.user_id left join osh_user pu on pu.id = p.user_id where c.status = 1 and c.parent_id in
#{parentId}
order by c.parent_id asc, c.create_time asc, c.id asc

select exists (
    select 1
    from osh_comment c
    inner join osh_comment_relation cr
        on cr.comment_id = c.id
       and cr.biz_type = #{bizType}
       and cr.biz_id = #{courseId}
    where c.id = #{commentId}
      and c.status = 1
      and (c.parent_id = 0 or c.parent_id is null)
)
